// Keep in sync with utils/tts.ts cache-key rule: trim + lowercase, tashkeel preserved.
export function normalizeAudioKey(text: string): string {
  return text.trim().toLowerCase();
}

export function getAudioAsset(text: string, dialect: AudioDialect = 'gulf'): any {
  const key = normalizeAudioKey(text);
  return AUDIO_MANIFEST[dialect]?.[key] ?? null;
}
